import React, { useState } from 'react'
import { Login } from './components/Login';
import { Register } from './components/Register';

export const IndexPage = () => {
    const [pageshow,setPageshow] = useState("login");
    return (
        <div className='IndexPage w-screen h-screen bg-repeat-x' 
        style={{
            backgroundImage:"url('./requiredfiles/wave.png')",
            backgroundPosition: "center bottom"
        }}>
            <div className="flex">
                <div className='pt-[20px] w-[50%] flex items-center'>
                    <img className="ml-[80px]" src="./requiredfiles/Logo.png" width={"80px"} alt="" />
                    <h1 className='ml-[10px] pt-[10px] text-[40px] font-[Sevillana]'>Secure Notes</h1>
                </div>
                {pageshow==="login" ? (
                    <div className='w-[50%] flex items-center justify-end'>
                        <div className="mr-[30px] cursor-pointer" onClick={()=>{setPageshow("register")}}>
                            <h1 className='text-[20px] font-[Barlow]'>Registers</h1>
                        </div>                    
                        <div className="mr-[60px] cursor-pointer py-[5px] px-[15px] bg-[#845EC2] text-white rounded-md " style={{boxShadow:"1px 1px 30px 1px #845EC2"}} onClick={()=>{setPageshow("login")}}>
                            <h1 className='text-[20px] font-[Barlow]'>Login</h1>
                        </div>
                    </div>
                ): (
                    <div className='w-[50%] flex items-center justify-end'>
                        <div className="mr-[30px] cursor-pointer py-[5px] px-[15px] bg-[#845EC2] text-white rounded-md " style={{boxShadow:"1px 1px 30px 1px #845EC2"}} onClick={()=>{setPageshow("register")}}>
                            <h1 className='text-[20px] font-[Barlow]'>Registers</h1>
                        </div>                    
                        <div className="mr-[80px] cursor-pointer" onClick={()=>{setPageshow("login")}}>
                            <h1 className='text-[20px] font-[Barlow]'>Login</h1>
                        </div>
                    </div>
                )}
            </div>
            
            <div className='page mt-[50px] flex justify-center'>
                {pageshow==="login" ? <Login/> : <Register/>}  
            </div>         
            
        </div>
    )
}
